let _allConstructorStandings=[],_userFavTeams=[];async function initConstructorsPage(){await loadConstructorsData(SeasonState.get()),initFilters(),window.addEventListener("seasonChanged",({detail:t})=>loadConstructorsData(t.year))}async function loadFavTeamIds(){if(AuthState.isLoggedIn())try{const t=await Favorites.list();_userFavTeams=(t||[]).filter(t=>t.constructor_id).map(t=>t.constructor_id)}catch(t){_userFavTeams=[]}else _userFavTeams=[]}async function loadConstructorsData(t){const n=document.getElementById("constructors-table-wrap");showLoading(n),await loadFavTeamIds();try{if(_allConstructorStandings=await Standings.constructors(t),!_allConstructorStandings?.length)return void showEmpty(n,"Нет данных","Таблица ещё не сформирована");renderConstructorsChart("chart-teams-pts",_allConstructorStandings),populateCountryFilter(_allConstructorStandings),renderConstructorsTable(n,_allConstructorStandings)}catch(t){showError(n,t.message)}}function renderConstructorsTable(t,n){if(!n?.length)return void showEmpty(t,"Команды не найдены");t.innerHTML=`\n    <table id="constructors-table">\n      <thead>\n        <tr>\n          <th style="width:48px;">Место</th>\n          <th>Команда</th>\n          <th>Страна</th>\n          <th>Болид</th>\n          <th>Гонщики</th>\n          <th data-sort="points" class="text-right">Очки</th>\n          <th data-sort="wins"   class="text-right">Победы</th>\n          <th data-sort="podiums" class="text-right">Подиумы</th>\n          <th style="width:80px;"></th>\n        </tr>\n      </thead>\n      <tbody>\n        ${n.map(t=>{const n=t.position,e=t.constructor||{},s=getConstructorName(t,"—"),a=e.logo_url||"",o=e.car_image_url||"",r=t.constructor_id,i=(t.drivers||[]).map(t=>t.last_name||t.full_name).join(", ")||"—";return`\n            <tr class="${getRowHighlight(n)}">\n              <td class="table-position"><span class="${getPositionClass(n)}">${n}</span>${getPosChangeHtml(n,t.previous_position)}</td>\n              <td>\n                <div class="driver-cell">\n                  ${a?`<img src="${escapeHtml(a)}" class="team-logo" alt="${escapeHtml(s)}" onerror="this.style.display='none'">`:""}\n                  <div>\n                    <div class="driver-name">${escapeHtml(s)}</div>\n                    ${o?`<img src="${escapeHtml(o)}" style="height:20px;margin-top:2px;" alt="car" onerror="this.style.display='none'">`:""}\n                  </div>\n                </div>\n              </td>\n              <td class="muted">${escapeHtml(e.nationality||"—")}</td>\n              <td class="muted" style="font-size:.82rem;">${escapeHtml(e.car_name||"—")}</td>\n              <td class="muted" style="font-size:.82rem;">${escapeHtml(i)}</td>\n              <td class="text-right number" data-col="points" data-value="${t.points}"><strong style="color:var(--teal)">${t.points}</strong></td>\n              <td class="text-right number" data-col="wins"    data-value="${t.wins||0}">${t.wins||0}</td>\n              <td class="text-right number" data-col="podiums" data-value="${t.podiums||0}">${t.podiums||0}</td>\n              <td>\n                <div style="display:flex;gap:6px;justify-content:flex-end;">\n                  <a href="/constructor-detail.html?id=${r}" class="btn btn-ghost btn-sm btn-icon">→</a>\n                  ${AuthState.isLoggedIn()?`<button class="btn-favorite ${l=r,_userFavTeams.includes(l)?"active":""}" onclick="toggleFavoriteConstructor(${r}, this)">★</button>`:""}\n                </div>\n              </td>\n            </tr>\n          `;var l}).join("")}\n      </tbody>\n    </table>\n  `,initSortableTable(document.getElementById("constructors-table"))}function populateCountryFilter(t){const n=document.getElementById("filter-country");if(!n)return;const e=[...new Set(t.map(t=>t.constructor?.nationality).filter(Boolean))].sort();n.innerHTML='<option value="">Все страны</option>'+e.map(t=>`<option value="${escapeHtml(t)}">${escapeHtml(t)}</option>`).join("")}function applyFilters(){const t=document.getElementById("search-team")?.value.toLowerCase()||"",n=document.getElementById("filter-country")?.value||"",e=document.getElementById("sort-by")?.value||"points";let s=_allConstructorStandings.filter(e=>{const s=getConstructorName(e,"").toLowerCase();return!(t&&!s.includes(t))&&(!n||e.constructor?.nationality===n)});"wins"===e&&s.sort((t,n)=>(n.wins||0)-(t.wins||0)),"name"===e&&s.sort((t,n)=>getConstructorName(t,"").localeCompare(getConstructorName(n,""),"ru")),renderConstructorsTable(document.getElementById("constructors-table-wrap"),s)}function initFilters(){["search-team","filter-country","sort-by"].forEach(t=>{document.getElementById(t)?.addEventListener("input",applyFilters),document.getElementById(t)?.addEventListener("change",applyFilters)})}document.addEventListener("DOMContentLoaded",initConstructorsPage);